import React, {
  useState,
  useCallback,
  useRef,
  useImperativeHandle,
  useMemo,
  useEffect,
} from "react";
import { cn, cva } from "../../lib/utils";
import { useTranslation } from "react-i18next";
import { Token } from "../token/Token";
import { BrowseFolderIcon } from "../../icons/BrowseFolder";
import { DeclineIcon } from "../../icons/Decline";
import { SysEnter2Icon } from "../../icons/SysEnter2";
import { ErrorIcon } from "../../icons/Error";
import { WarningIcon } from "../../icons/Warning";
import { InformationIcon } from "../../icons/Information";
import { Button } from "../button";
import { ButtonDesign, ButtonSize } from "../../types/button";
import {
  type FileUploaderProps,
  FileUploaderSize,
  ValueState,
} from "../../types/file-uploader";

/**
 * Build a FileList from an array of File objects.
 * Uses DataTransfer when available, otherwise creates a mock FileList.
 */
function buildFileList(files: File[]): FileList {
  if (typeof DataTransfer !== "undefined") {
    const dt = new DataTransfer();
    files.forEach((f) => dt.items.add(f));
    return dt.files;
  }
  // Fallback for environments without DataTransfer (e.g., jsdom in tests)
  const list = Object.create(FileList.prototype);
  files.forEach((f, i) => { list[i] = f; });
  Object.defineProperty(list, "length", { value: files.length });
  list.item = (index: number) => list[index] ?? null;
  list[Symbol.iterator] = function* () {
    for (let i = 0; i < files.length; i++) yield list[i];
  };
  return list as FileList;
}

/** Generate a stable unique ID for use with aria-describedby */
let descIdCounter = 0;
function useStableId(prefix: string) {
  const ref = useRef(`${prefix}-${++descIdCounter}`);
  return ref.current;
}

/**
 * Container variants matching Input.tsx CVA pattern with sapphire-* classes.
 * Covers: Regular, Hover, Pressed/Focus, Disabled states per Figma spec.
 */
const containerVariants = cva(
  [
    "flex items-center w-full border bg-sapphire-canvas-primary",
    "overflow-clip transition-colors relative",
    "pr-1 py-1 gap-1",
    "cursor-pointer outline-none",
  ],
  {
    variants: {
      size: {
        [FileUploaderSize.Large]: [
          "h-10 rounded-lg pl-1",
          "focus:border-2 focus:pl-[3px] focus:pr-[3px] focus:py-[3px]",
        ],
        [FileUploaderSize.Medium]: [
          "h-8 rounded pl-0.5",
          "focus:border-2 focus:pl-px focus:pr-[3px] focus:py-[3px]",
        ],
      },
      valueState: {
        [ValueState.None]:
          "border-sapphire-border-active hover:border-sapphire-border-accent focus:border-sapphire-border-accent",
        [ValueState.Positive]:
          "bg-sapphire-positive-bg hover:bg-sapphire-canvas-primary focus:bg-sapphire-canvas-primary border-sapphire-positive focus:border-sapphire-positive",
        [ValueState.Negative]:
          "bg-sapphire-negative-bg hover:bg-sapphire-canvas-primary focus:bg-sapphire-canvas-primary border-sapphire-negative focus:border-sapphire-negative",
        [ValueState.Critical]:
          "bg-sapphire-warning-bg hover:bg-sapphire-canvas-primary focus:bg-sapphire-canvas-primary border-sapphire-warning focus:border-sapphire-warning",
        [ValueState.Information]:
          "bg-sapphire-info-bg hover:bg-sapphire-canvas-primary focus:bg-sapphire-canvas-primary border-sapphire-info focus:border-sapphire-info",
      },
      disabled: {
        true: "opacity-40 cursor-not-allowed pointer-events-none",
        false: "",
      },
      dragOver: {
        true: "border-sapphire-border-accent border-2 pl-[3px] pr-[3px] py-[3px]",
        false: "",
      },
    },
    defaultVariants: {
      size: FileUploaderSize.Large,
      valueState: ValueState.None,
      disabled: false,
      dragOver: false,
    },
  }
);

/**
 * Value state icon mapping (same as Input.tsx)
 */
const valueStateIcons: Record<ValueState, React.ElementType | null> = {
  [ValueState.None]: null,
  [ValueState.Positive]: SysEnter2Icon,
  [ValueState.Negative]: ErrorIcon,
  [ValueState.Critical]: WarningIcon,
  [ValueState.Information]: InformationIcon,
};

/**
 * Value state message color mapping
 */
const valueStateMessageColors: Record<ValueState, string> = {
  [ValueState.None]: "",
  [ValueState.Positive]: "text-sapphire-positive",
  [ValueState.Negative]: "text-sapphire-negative",
  [ValueState.Critical]: "text-sapphire-warning",
  [ValueState.Information]: "text-sapphire-info",
};

/**
 * FileUploader component
 *
 * A file upload control that allows users to select files via browse dialog
 * or drag-and-drop. Supports single/multiple files, file type filtering,
 * file size validation, and value state feedback.
 *
 * @example
 * ```tsx
 * <FileUploader
 *   accept=".pdf,.doc"
 *   multiple
 *   maxFileSize={5}
 *   onChange={({ files }) => console.log(files)}
 * />
 * ```
 */
function FileUploaderBase({
  size = FileUploaderSize.Large,
  accept,
  multiple = false,
  maxFileSize,
  hideInput = false,
  placeholder,
  value,
  disabled = false,
  required = false,
  valueState = ValueState.None,
  valueStateMessage,
  name,
  accessibleName,
  accessibleNameRef,
  accessibleDescription,
  accessibleDescriptionRef,
  onChange,
  onFileSizeExceed,
  children,
  className,
  style,
  id,
  "data-testid": dataTestId,
  ref,
}: FileUploaderProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const dragCounterRef = useRef(0);
  const fileNamesRef = useRef<string[]>([]);
  const tokenAreaRef = useRef<HTMLDivElement>(null);
  const [fileNames, setFileNames] = useState<string[]>([]);
  const [isDragOver, setIsDragOver] = useState(false);
  const [isFocused, setIsFocused] = useState(false);
  const [focusedTokenIndex, setFocusedTokenIndex] = useState(-1);
  const { t } = useTranslation("fx");
  const descriptionId = useStableId("fu-desc");

  const resolvedValueState = valueState as ValueState;
  const isNegativeState = resolvedValueState === ValueState.Negative;
  const isMedium = size === FileUploaderSize.Medium;

  // Resolve placeholder based on multiple prop
  const resolvedPlaceholder = placeholder ?? (
    multiple
      ? t("FILEUPLOADER_PLACEHOLDER_MULTIPLE")
      : t("FILEUPLOADER_PLACEHOLDER")
  );

  // Derive display names from value prop or internal state
  const displayNames = useMemo(() => {
    if (value !== undefined && value !== "") {
      return value.split(",").map((n) => n.trim()).filter(Boolean);
    }
    return fileNames;
  }, [value, fileNames]);

  const hasFiles = displayNames.length > 0;
  const isMultiDisplay = displayNames.length > 1;

  // Overflow detection for multi-file display (non-focused state)
  const [visibleCount, setVisibleCount] = useState(displayNames.length);
  const nMoreLabelRef = useRef<HTMLSpanElement>(null);

  useEffect(() => {
    // Reset visible count when files change
    setVisibleCount(displayNames.length);
  }, [displayNames.length]);

  useEffect(() => {
    if (!isMultiDisplay || isFocused || !tokenAreaRef.current) return;

    const area = tokenAreaRef.current;

    const calculateVisible = () => {
      if (!area) return;
      const areaWidth = area.getBoundingClientRect().width;
      if (areaWidth === 0) return;

      // Measure the "n more" label width
      const nMoreWidth = nMoreLabelRef.current
        ? nMoreLabelRef.current.getBoundingClientRect().width + 8
        : 60;

      // Measure each token's width
      const tokenEls = Array.from(
        area.querySelectorAll('[data-part="root"]')
      ) as HTMLElement[];

      const gap = 4; // gap-1
      let usedWidth = 0;
      let fitCount = 0;

      for (let i = 0; i < tokenEls.length; i++) {
        const el = tokenEls[i];
        // Temporarily show hidden tokens to measure
        const wasHidden = el.classList.contains("hidden");
        if (wasHidden) el.classList.remove("hidden");
        const w = el.getBoundingClientRect().width;
        if (wasHidden) el.classList.add("hidden");

        const needed = w + (i > 0 ? gap : 0);
        const remaining = tokenEls.length - i - 1;
        const reserve = remaining > 0 ? nMoreWidth : 0;

        if (usedWidth + needed + reserve > areaWidth && fitCount > 0) {
          break;
        }
        usedWidth += needed;
        fitCount++;
      }

      setVisibleCount(fitCount);
    };

    const observer = new ResizeObserver(() => {
      requestAnimationFrame(calculateVisible);
    });
    observer.observe(area);
    calculateVisible();

    return () => observer.disconnect();
  }, [isMultiDisplay, isFocused, displayNames]);

  const overflowCount = isMultiDisplay ? Math.max(0, displayNames.length - visibleCount) : 0;

  // Validate files against maxFileSize
  const validateFiles = useCallback(
    (files: FileList): FileList | null => {
      if (maxFileSize === undefined || maxFileSize <= 0) return files;

      const exceededFiles: Array<{ fileName: string; fileSize: number }> = [];
      const validFiles: File[] = [];

      for (let i = 0; i < files.length; i++) {
        const file = files[i];
        const fileSizeMB = file.size / 1024 / 1024;
        if (fileSizeMB > maxFileSize) {
          exceededFiles.push({ fileName: file.name, fileSize: fileSizeMB });
        } else {
          validFiles.push(file);
        }
      }

      if (exceededFiles.length > 0) {
        onFileSizeExceed?.({ filesData: exceededFiles });
      }

      if (validFiles.length === 0 && exceededFiles.length > 0) {
        return null;
      }

      return buildFileList(validFiles);
    },
    [maxFileSize, onFileSizeExceed]
  );

  // Filter files by accept prop (needed for drag-and-drop; native input handles dialog)
  const filterByAccept = useCallback(
    (files: FileList): FileList => {
      if (!accept) return files;

      const acceptTypes = accept.split(",").map((t) => t.trim().toLowerCase());
      const matched: File[] = [];

      for (let i = 0; i < files.length; i++) {
        const file = files[i];
        const parts = file.name.split(".");
        const fileExt = parts.length > 1 ? "." + parts.pop()?.toLowerCase() : "";
        const fileMime = file.type.toLowerCase();

        const matches = acceptTypes.some((type) => {
          if (type.startsWith(".")) {
            return fileExt === type;
          }
          if (type.endsWith("/*")) {
            return fileMime.startsWith(type.slice(0, -1));
          }
          return fileMime === type;
        });

        if (matches) {
          matched.push(file);
        }
      }

      return buildFileList(matched);
    },
    [accept]
  );

  // Open the native file browser
  const openFileBrowser = useCallback(() => {
    if (disabled) return;
    // Reset value to allow re-selecting the same file
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
    fileInputRef.current?.click();
  }, [disabled]);

  // Clear all selected files
  const clearFiles = useCallback(() => {
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
    fileNamesRef.current = [];
    setFileNames([]);
    onChange?.({ files: null });
  }, [onChange]);

  // Handle native input change
  const handleNativeChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const files = e.target.files;
      if (!files || files.length === 0) {
        // Chrome fires change on cancel — only clear if we had files
        if (fileNamesRef.current.length > 0) {
          clearFiles();
        }
        return;
      }

      const validFiles = validateFiles(files);
      if (!validFiles || validFiles.length === 0) {
        return;
      }

      const names = Array.from(validFiles).map((f) => f.name);
      fileNamesRef.current = names;
      setFileNames(names);
      onChange?.({ files: validFiles });
    },
    [validateFiles, clearFiles, onChange]
  );

  // Handle container click
  const handleContainerClick = useCallback(() => {
    openFileBrowser();
  }, [openFileBrowser]);

  // Handle keyboard
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (disabled) return;

      switch (e.key) {
        case "Enter":
        case " ":
          e.preventDefault();
          openFileBrowser();
          break;
        case "F4":
          e.preventDefault();
          openFileBrowser();
          break;
        case "Delete":
          e.preventDefault();
          if (hasFiles) {
            clearFiles();
          }
          break;
        case "ArrowRight":
          // Move focus to first token when multiple files
          if (displayNames.length > 1 && isFocused) {
            e.preventDefault();
            setFocusedTokenIndex(0);
            const tokens = tokenAreaRef.current?.querySelectorAll('[data-part="root"]');
            (tokens?.[0] as HTMLElement)?.focus();
          }
          break;
      }

      // Alt+Up / Alt+Down open file browser
      if (e.altKey && (e.key === "ArrowUp" || e.key === "ArrowDown")) {
        e.preventDefault();
        openFileBrowser();
      }
    },
    [disabled, openFileBrowser, hasFiles, clearFiles, displayNames.length, isFocused]
  );

  // Handle arrow key navigation between tokens
  const handleTokenKeyDown = useCallback(
    (e: React.KeyboardEvent, index: number) => {
      if (e.key === "ArrowRight") {
        e.preventDefault();
        e.stopPropagation();
        if (index < displayNames.length - 1) {
          const next = index + 1;
          setFocusedTokenIndex(next);
          const tokens = tokenAreaRef.current?.querySelectorAll('[data-part="root"]');
          const el = tokens?.[next] as HTMLElement;
          el?.focus();
          el?.scrollIntoView({ block: "nearest", inline: "nearest" });
        }
      } else if (e.key === "ArrowLeft") {
        e.preventDefault();
        e.stopPropagation();
        if (index > 0) {
          const prev = index - 1;
          setFocusedTokenIndex(prev);
          const tokens = tokenAreaRef.current?.querySelectorAll('[data-part="root"]');
          const el = tokens?.[prev] as HTMLElement;
          el?.focus();
          el?.scrollIntoView({ block: "nearest", inline: "nearest" });
        } else {
          // First token → return focus to the container
          setFocusedTokenIndex(-1);
          containerRef.current?.focus();
        }
      }
    },
    [displayNames.length]
  );

  // Drag and drop handlers
  const handleDragOver = useCallback(
    (e: React.DragEvent) => {
      if (disabled) return;
      e.preventDefault();
      e.stopPropagation();
    },
    [disabled]
  );

  const handleDragEnter = useCallback(
    (e: React.DragEvent) => {
      if (disabled) return;
      e.preventDefault();
      e.stopPropagation();
      dragCounterRef.current++;
      setIsDragOver(true);
    },
    [disabled]
  );

  const handleDragLeave = useCallback(
    (e: React.DragEvent) => {
      if (disabled) return;
      e.preventDefault();
      e.stopPropagation();
      dragCounterRef.current--;
      if (dragCounterRef.current <= 0) {
        dragCounterRef.current = 0;
        setIsDragOver(false);
      }
    },
    [disabled]
  );

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      if (disabled) return;
      e.preventDefault();
      e.stopPropagation();
      dragCounterRef.current = 0;
      setIsDragOver(false);

      let droppedFiles = e.dataTransfer.files;
      if (!droppedFiles || droppedFiles.length === 0) return;

      // If not multiple, take only the first file
      if (!multiple && droppedFiles.length > 1) {
        droppedFiles = buildFileList([droppedFiles[0]]);
      }

      // Filter by accept types (native input doesn't restrict drag-and-drop)
      droppedFiles = filterByAccept(droppedFiles);
      if (droppedFiles.length === 0) return;

      // Validate file sizes
      const validFiles = validateFiles(droppedFiles);
      if (!validFiles || validFiles.length === 0) return;

      const names = Array.from(validFiles).map((f) => f.name);
      fileNamesRef.current = names;
      setFileNames(names);
      onChange?.({ files: validFiles });
    },
    [disabled, multiple, filterByAccept, validateFiles, onChange]
  );

  // Handle clear button click
  const handleClearClick = useCallback(
    (detail: { originalEvent: React.SyntheticEvent; isKeyboard: boolean }) => {
      detail.originalEvent.stopPropagation();
      clearFiles();
    },
    [clearFiles]
  );

  // Handle browse button click
  const handleBrowseClick = useCallback(
    (detail: { originalEvent: React.SyntheticEvent; isKeyboard: boolean }) => {
      detail.originalEvent.stopPropagation();
      openFileBrowser();
    },
    [openFileBrowser]
  );

  // Imperative API
  useImperativeHandle(
    ref,
    () => ({
      focus() {
        containerRef.current?.focus();
      },
      blur() {
        containerRef.current?.blur();
      },
      openFileBrowser() {
        openFileBrowser();
      },
      clear() {
        clearFiles();
      },
      get files() {
        return fileInputRef.current?.files ?? null;
      },
      get nativeInput() {
        return fileInputRef.current;
      },
    }),
    [openFileBrowser, clearFiles]
  );

  // Value state icon
  const ValueStateIcon = valueStateIcons[resolvedValueState];

  return (
    <div
      className={cn("w-full", className)}
      style={style}
      id={id}
      data-testid={dataTestId}
    >
      {/* Hidden native file input */}
      <input
        ref={fileInputRef}
        type="file"
        accept={accept}
        multiple={multiple}
        name={name}
        required={required}
        disabled={disabled}
        tabIndex={-1}
        aria-hidden="true"
        className="sr-only"
        onChange={handleNativeChange}
        data-testid={dataTestId ? `${dataTestId}-input` : undefined}
      />

      {hideInput ? (
        /* Button-only mode: render children as trigger */
        <div
          role="button"
          tabIndex={disabled ? -1 : 0}
          onClick={disabled ? undefined : handleContainerClick}
          onKeyDown={disabled ? undefined : handleKeyDown}
          aria-label={accessibleName}
          aria-labelledby={accessibleNameRef}
          aria-disabled={disabled || undefined}
        >
          {children}
        </div>
      ) : (
        /* Standard mode: styled container */
        <div
          ref={containerRef}
          tabIndex={disabled ? -1 : 0}
          role="group"
          aria-roledescription={t("FILEUPLOADER_ROLE_DESCRIPTION")}
          aria-label={accessibleName}
          aria-labelledby={accessibleNameRef}
          aria-describedby={accessibleDescription ? descriptionId : accessibleDescriptionRef}
          aria-required={required || undefined}
          aria-invalid={isNegativeState || undefined}
          aria-haspopup="dialog"
          className={cn(
            containerVariants({
              size: size as FileUploaderSize,
              valueState: resolvedValueState,
              disabled,
              dragOver: isDragOver,
            })
          )}
          onClick={handleContainerClick}
          onKeyDown={handleKeyDown}
          onFocus={() => setIsFocused(true)}
          onBlur={(e) => {
            // Only blur if focus leaves the container entirely
            if (!containerRef.current?.contains(e.relatedTarget as Node)) {
              setIsFocused(false);
              setFocusedTokenIndex(-1);
            }
          }}
          onDragOver={handleDragOver}
          onDragEnter={handleDragEnter}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
        >
          {/* Hidden element for accessibleDescription */}
          {accessibleDescription && (
            <span id={descriptionId} className="sr-only">
              {accessibleDescription}
            </span>
          )}

          {/* Content area: placeholder or file tokens */}
          <div
            ref={tokenAreaRef}
            className={cn(
              "flex-1 min-w-0 flex items-center gap-1",
              isFocused && isMultiDisplay
                ? "overflow-x-auto scrollbar-none"
                : "overflow-hidden",
            )}
          >
            {hasFiles ? (
              displayNames.length === 1 ? (
                <Token text={displayNames[0]} readonly singleToken className="shrink min-w-0" />
              ) : isFocused ? (
                displayNames.map((fileName, idx) => (
                  <span
                    key={fileName}
                    onKeyDown={(e) => handleTokenKeyDown(e, idx)}
                    className="shrink-0"
                  >
                    <Token
                      text={fileName}
                      readonly
                      tabIndex={idx === focusedTokenIndex ? 0 : -1}
                    />
                  </span>
                ))
              ) : (
                <>
                  {displayNames.map((fileName, idx) => (
                    <Token
                      key={fileName}
                      text={fileName}
                      readonly
                      className={idx >= visibleCount ? "hidden" : "shrink-0"}
                    />
                  ))}
                  {overflowCount > 0 && (
                    <span
                      ref={nMoreLabelRef}
                      className="inline-block whitespace-nowrap shrink-0 text-sm font-normal text-sapphire-brand-foreground cursor-pointer hover:underline"
                    >
                      {t("TOKENIZER_SHOW_MORE", { count: overflowCount })}
                    </span>
                  )}
                </>
              )
            ) : (
              <span className="text-sapphire-text-tertiary italic text-sm truncate select-none pl-2.5">
                {resolvedPlaceholder}
              </span>
            )}
          </div>

          {/* Clear button — visible when files are present */}
          {hasFiles && !disabled && (
            <span onMouseDown={(e) => e.preventDefault()}>
              <Button
                design={ButtonDesign.SecondaryNeutral}
                size={isMedium ? ButtonSize.Small : ButtonSize.Medium}
                iconOnly
                icon={<span className={cn("inline-flex items-center justify-center", isMedium ? "h-3 w-3" : "h-4 w-4")}><DeclineIcon className="h-full w-full" /></span>}
                tabIndex={-1}
                onClick={handleClearClick}
                accessibleName={t("FILEUPLOADER_CLEAR_TOOLTIP")}
                className="shrink-0"
                data-part="clear"
              />
            </span>
          )}

          {/* Browse button — always visible */}
          <span onMouseDown={(e) => e.preventDefault()}>
            <Button
              design={ButtonDesign.SecondaryNeutral}
              size={isMedium ? ButtonSize.Small : ButtonSize.Medium}
              iconOnly
              icon={<span className={cn("inline-flex items-center justify-center", isMedium ? "h-3 w-3" : "h-4 w-4")}><BrowseFolderIcon className="h-full w-full" /></span>}
              tabIndex={-1}
              onClick={handleBrowseClick}
              accessibleName={t("FILEUPLOADER_BROWSE_TOOLTIP")}
              className="shrink-0"
              data-part="browse"
            />
          </span>
        </div>
      )}

      {/* Value state message */}
      {valueStateMessage && resolvedValueState !== ValueState.None && (
        <div
          role={isNegativeState ? "alert" : undefined}
          aria-live={isNegativeState ? "assertive" : "polite"}
          className={cn(
            "mt-1 text-xs flex items-start gap-1",
            valueStateMessageColors[resolvedValueState]
          )}
        >
          {ValueStateIcon && <ValueStateIcon className="h-3 w-3 mt-0.5 shrink-0" />}
          <span>{valueStateMessage}</span>
        </div>
      )}
    </div>
  );
}

export const FileUploader = React.memo(FileUploaderBase);
FileUploader.displayName = "FileUploader";
